var Layout = (function () {
    // Toggle "page-on-scroll" class when scrolling
    var handleScroll = function () {
        if ($(window).scrollTop() > 60) {
            $("body").addClass("page-on-scroll");
        } else {
            $("body").removeClass("page-on-scroll");
        }
    };

    // Navbar collapse, smooth scroll, and scrollspy setup
    var handleNavbar = function () {
        if ($(".navbar").offset().top > 150) {
            $(".navbar-fixed-top").addClass("top-nav-collapse");
        }

        $(window).scroll(function () {
            if ($(".navbar").offset().top > 150) {
                $(".navbar-fixed-top").addClass("top-nav-collapse");
            } else {
                $(".navbar-fixed-top").removeClass("top-nav-collapse");
            }
        });

        var offsetTop = $(".navbar-fixed-top").height() - 20;

        $(".js_nav-item a").bind("click", function (event) {
            var target = $($(this).attr("href")).offset().top;
            $("html, body").stop().animate({ scrollTop: target - offsetTop }, 600);
            event.preventDefault();
        });

        $("body").scrollspy({
            target: ".navbar-fixed-top",
            offset: offsetTop + 2
        });

        $(window).scroll(function () {
            $(".navbar-collapse.in").collapse("hide");
        });
    };

    // Fullscreen carousel setup
    var handleCarousel = function () {
        var items = $(".carousel .item");
        var windowHeight = $(window).height();

        items.eq(0).addClass("active");
        items.height(windowHeight);
        items.addClass("full-screen");

        $(".carousel img").each(function () {
            var src = $(this).attr("src");
            var color = $(this).attr("data-color");
            $(this).parent().css({
                "background-image": "url(" + src + ")",
                "background-color": color
            });
            $(this).remove();
        });

        $(window).on("resize", function () {
            windowHeight = $(window).height();
            items.height(windowHeight);
        });
    };

    // Equal height sections (auto height adjustment)
    var handleEqualHeight = function () {
        $("[data-auto-height]").each(function () {
            var parent = $(this);
            var elements = $("[data-height]", parent);
            var maxHeight = 0;
            var mode = parent.attr("data-mode");
            var offset = parseInt(parent.attr("data-offset") ? parent.attr("data-offset") : 0);

            elements.each(function () {
                if ($(this).attr("data-height") == "height") {
                    $(this).css("height", "");
                } else {
                    $(this).css("min-height", "");
                }

                var elementHeight = (mode == "base-height") ? $(this).outerHeight() : $(this).outerHeight(true);
                if (elementHeight > maxHeight) maxHeight = elementHeight;
            });

            maxHeight += offset;

            elements.each(function () {
                if ($(this).attr("data-height") == "height") {
                    $(this).css("height", maxHeight);
                } else {
                    $(this).css("min-height", maxHeight);
                }
            });

            if (parent.attr("data-related")) {
                $(parent.attr("data-related")).css("height", parent.height());
            }
        });
    };

    // Work popup overlay handling
    var handleWorkPopup = function () {
        var overlay = $(".work-popup-overlay");
        var closeBtn = $(".work-popup-close");
        var trigger = $(".work-popup-trigger");

        trigger.on("click", function () {
            $(this)
                .find(".work-popup-overlay")
                .removeClass("work-popup-overlay-show")
                .addClass("work-popup-overlay-show");
        });

        closeBtn.on("click", function (event) {
            event.stopPropagation();
            overlay.removeClass("work-popup-overlay-show");
        });
    };

    // Public methods
    return {
        init: function () {
            handleScroll();
            handleNavbar();
            handleCarousel();
            handleEqualHeight();
            handleWorkPopup();

            $(window).scroll(function () {
                handleScroll();
            });
        },

        getViewPort: function () {
            var win = window;
            var prefix = "inner";

            if (!("innerWidth" in window)) {
                prefix = "client";
                win = document.documentElement || document.body;
            }

            return {
                width: win[prefix + "Width"],
                height: win[prefix + "Height"]
            };
        }
    };
})();

// Initialize on document ready
$(document).ready(function () {
    Layout.init();
});
